import React, { useState } from 'react';
import { GoogleMap, LoadScript, DirectionsService, DirectionsRenderer } from '@react-google-maps/api';
import api from '../services/api';
import mapStyles from '../components/mapStyles';

const containerStyle = {
  width: '100%',
  height: '600px',
};

const center = {
  lat: 37.7749,
  lng: -122.4194,
};

const RouteOptimization = () => {
  const [start, setStart] = useState('');
  const [end, setEnd] = useState('');
  const [directions, setDirections] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [routeDetails, setRouteDetails] = useState(null);

  const handleOptimizeRoute = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await api.post('/routes/optimize', { start, end });
      setDirections(response.data);
      setRouteDetails({
        distance: response.data.routes[0].legs[0].distance / 1000, // Convert to km
        duration: response.data.routes[0].legs[0].duration,
      });
    } catch (err) {
      setError('Failed to optimize route. Please try again.');
      console.error('Route optimization error:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <h2 className="g-title">Route Optimization</h2>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 stat-card">
          <h3 className="text-lg font-semibold mb-4">Route Map</h3>
          <LoadScript googleMapsApiKey="YOUR_GOOGLE_MAPS_API_KEY">
            <GoogleMap
              mapContainerStyle={containerStyle}
              center={center}
              zoom={10}
              options={{ styles: mapStyles }}
            >
              {directions && <DirectionsRenderer directions={directions} />}
            </GoogleMap>
          </LoadScript>
        </div>
        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Route Planner</h3>
          <form onSubmit={handleOptimizeRoute} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Start Location</label>
              <input
                type="text"
                className="g-input"
                placeholder="Enter start location"
                value={start}
                onChange={(e) => setStart(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">End Location</label>
              <input
                type="text"
                className="g-input"
                placeholder="Enter end location"
                value={end}
                onChange={(e) => setEnd(e.target.value)}
                required
              />
            </div>
            <button type="submit" className="g-btn" disabled={loading}>
              {loading ? 'Optimizing...' : 'Optimize Route'}
            </button>
            {error && <p className="g-error">{error}</p>}
          </form>
          {routeDetails && (
            <div className="mt-4">
              <h4 className="text-md font-semibold">Route Details</h4>
              <p>Distance: {routeDetails.distance.toFixed(2)} km</p>
              <p>Duration: {Math.floor(routeDetails.duration / 60)} min</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default RouteOptimization;
